package com.gal.issueTracker.implementation;

import com.gal.issueTracker.model.Employee;
import com.gal.issueTracker.model.Issue;
import com.gal.issueTracker.repo.EmployeeRepo;
import com.gal.issueTracker.service.EmployeeService;
import org.springframework.stereotype.Component;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

@Service
public class EmployeeImpl implements EmployeeService {

    EmployeeRepo employeeRepo;
    public EmployeeImpl(EmployeeRepo employeeRepo) {
        this.employeeRepo = employeeRepo;
    }

    @Override
    public Employee findEmployeeById(int id) {
        return employeeRepo.findById(id).orElse(null);
    }

    @Override
    public Employee addEmployee(Employee employee) {
        return employeeRepo.save(employee);
    }

    @Override
    public Employee updateEmployee(Employee employee) {
        return employeeRepo.save(employee);
    }

    @Override
    public void deleteEmployee(int id) {
        employeeRepo.deleteById(id);
    }

    @Override
    public List<Issue> findAllIssuesByEmployeeId(int id) {
        return employeeRepo.findAllIssuesByEmployeeId(id);
    }

    @Override
    public List<Issue> findAllIssuesByEmployeeIdAndByMonth(int id, int month) {
        return employeeRepo.findAllIssuesByEmployeeIdAndByMonth(id, month);
    }

    @Override
    public List<Issue> findAllUnresolvedIssuesByEmployeeId(int id) {
        return employeeRepo.findAllUnresolvedIssuesByEmployeeId(id);
    }
}

package com.gal.issueTracker.api;

import com.gal.issueTracker.model.Employee;
import com.gal.issueTracker.service.IssueService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;

import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.test.web.servlet.MockMvc;

import java.util.ArrayList;
import java.util.List;

import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(IssueController.class)
class IssueControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private IssueService issueService;

    @Test
    void testGetAllEmployeesWhoRaisedIssueByMonth() throws Exception {
        Employee employee = new Employee(1,"Gale");
        Employee employee2 = new Employee(2,"Chris");
        Employee employee3 = new Employee(3,"Raj");
        List<Employee> list = new ArrayList<>(List.of(employee,employee2,employee3));

        when(issueService.findAllEmployeesWhoRaisedIssueByMonth(3)).thenReturn(list);

        mockMvc.perform(get("/issue/emplWhoRaisedIssue/3")
                .contentType("application/json"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].id").value(1))
                .andExpect(jsonPath("$[0].name").value("Gale"))
                .andExpect(jsonPath("$[1].id").value(2))
                .andExpect(jsonPath("$[1].name").value("Chris"))
                .andExpect(jsonPath("$[2].id").value(3))
                .andExpect(jsonPath("$[2].name").value("Raj"));
    }

}

